  1	import { type Dispatch, type SetStateAction, useCallback, useMemo, useState } from 'react';
  2	
  3	import { isEmpty } from '@utils/helpers';
  4	
  5	import { type AttributeConfig, AttributeKind } from '../utils/types';
  6	
  7	type TextState = Record<string, string>;
  8	type ChecksState = Record<string, Set<string>>;
  9	
 10	export type AttributeFilters<T> = {
 11	  activeId: string;
 12	  checks: ChecksState;
 13	  chipsByAttr: Record<string, string[]>;
 14	  clearAll: () => void;
 15	  clearChecks: (id: string) => void;
 16	  clearText: (id: string) => void;
 17	  deleteChip: (attrId: string, chipLabel: string) => void;
 18	  deleteChipGroup: (attrId: string) => void;
 19	  hasAttrFilters: boolean;
 20	  predicate: (item: T) => boolean;
 21	  setActiveId: Dispatch<SetStateAction<string>>;
 22	  setTextValue: (id: string, value: string) => void;
 23	  text: TextState;
 24	  toggleCheck: (id: string, opt: string) => void;
 25	};
 26	
 27	export const useAttributeFilters = <T>(attributes: AttributeConfig<T>[]): AttributeFilters<T> => {
 28	  const [activeId, setActiveId] = useState(attributes[0]?.id ?? '');
 29	  const [text, setText] = useState<TextState>({});
 30	  const [checks, setChecks] = useState<ChecksState>({});
 31	
 32	  const setTextValue = useCallback((id: string, value: string) => {
 33	    setText((filters) => ({ ...filters, [id]: value }));
 34	  }, []);
 35	  const clearText = useCallback((id: string) => {
 36	    setText((filters) => ({ ...filters, [id]: '' }));
 37	  }, []);
 38	
 39	  const toggleCheck = useCallback((id: string, opt: string) => {
 40	    setChecks((filters) => {
 41	      const next = new Set(filters[id] ?? []);
 42	      if (next.has(opt)) {
 43	        next.delete(opt);
 44	      } else {
 45	        next.add(opt);
 46	      }
 47	      return { ...filters, [id]: next };
 48	    });
 49	  }, []);
 50	  const clearChecks = useCallback((id: string) => {
 51	    setChecks((filters) => ({ ...filters, [id]: new Set() }));
 52	  }, []);
 53	  const clearAll = useCallback(() => {
 54	    setText({});
 55	    setChecks({});
 56	    setActiveId(attributes[0]?.id ?? '');
 57	  }, [attributes]);
 58	
 59	  const predicate = useCallback(
 60	    (item: T) => {
 61	      for (const attr of attributes) {
 62	        if (attr.kind === AttributeKind.Text) {
 63	          const needle = (text[attr.id] ?? '').trim();
 64	          if (needle) {
 65	            const hay = (attr.getValue(item) ?? '').toString();
 66	            const def = (filter: string, data: string) => {
 67	              try {
 68	                return new RegExp(filter, 'iu').test(data);
 69	              } catch {
 70	                return data.toLowerCase().includes(filter.toLowerCase());
 71	              }
 72	            };
 73	            const match = attr.match ?? def;
 74	            if (!match(needle, hay)) return false;
 75	          }
 76	        } else {
 77	          const sel = checks[attr.id];
 78	          if (!isEmpty(sel)) {
 79	            const value = attr.getValues(item);
 80	            let arr: string[] = [];
 81	            if (Array.isArray(value)) {
 82	              arr = value;
 83	            } else if (value) {
 84	              arr = [value];
 85	            }
 86	            if (!arr.some((element) => sel.has(element))) return false;
 87	          }
 88	        }
 89	      }
 90	      return true;
 91	    },
 92	    [attributes, text, checks],
 93	  );
 94	
 95	  const chipsByAttr: Record<string, string[]> = useMemo(() => {
 96	    const out: Record<string, string[]> = {};
 97	    for (const attr of attributes) {
 98	      if (attr.kind === AttributeKind.Text) {
 99	        const value = (text[attr.id] ?? '').trim();
100	        out[attr.id] = value ? [value] : [];
101	      } else {
102	        const sel = checks[attr.id];
103	        const map = new Map(attr.options.map((option) => [option.id, option.label ?? option.id]));
104	        out[attr.id] = sel ? Array.from(sel).map((id) => map.get(id) ?? id) : [];
105	      }
106	    }
107	    return out;
108	  }, [attributes, text, checks]);
109	
110	  const hasAttrFilters = useMemo(() => !isEmpty(text) || !isEmpty(checks), [text, checks]);
111	
112	  const deleteChip = useCallback(
113	    (attrId: string, chipLabel: string) => {
114	      const attr = attributes.find((attribute) => attribute.id === attrId);
115	      if (!attr) return;
116	      if (attr.kind === AttributeKind.Text) {
117	        clearText(attrId);
118	        return;
119	      }
120	      const opt = attr.options.find((option) => (option.label ?? option.id) === chipLabel);
121	      if (opt) toggleCheck(attrId, opt.id);
122	    },
123	    [attributes, clearText, toggleCheck],
124	  );
125	
126	  const deleteChipGroup = useCallback(
127	    (attrId: string) => {
128	      const attr = attributes.find((attribute) => attribute.id === attrId);
129	      if (!attr) return;
130	      if (attr.kind === AttributeKind.Text) {
131	        clearText(attrId);
132	        return;
133	      }
134	      clearChecks(attrId);
135	    },
136	    [attributes, clearText, clearChecks],
137	  );
138	
139	  return {
140	    activeId,
141	    checks,
142	    chipsByAttr,
143	    clearAll,
144	    clearChecks,
145	    clearText,
146	    deleteChip,
147	    deleteChipGroup,
148	    hasAttrFilters,
149	    predicate,
150	    setActiveId,
151	    setTextValue,
152	    text,
153	    toggleCheck,
154	  };
155	};

