  8	  ToolbarToggleGroup,
  9	} from '@patternfly/react-core';
 10	import { FilterIcon } from '@patternfly/react-icons';
 11	import { useForkliftTranslation } from '@utils/i18n';
 12	
 13	import FilterAttributeSelect from './components/FilterAttributeSelect';
 14	import FilterValueMultiSelect from './components/FilterValueMultiSelect';
 15	import type { AttributeFilters } from './hooks/useAttributeFilters';
 16	import { type AttributeConfig, AttributeKind } from './utils/types';
 17	
 18	type AttributeFiltersToolbarProps<T> = {
 19	  attributes: AttributeConfig<T>[];
 20	} & AttributeFilters<T>;
 21	
 22	export const AttributeFiltersToolbar = <T,>({
 23	  activeId,
 24	  attributes,
 25	  checks,
 26	  chipsByAttr,
 27	  clearText,
 28	  deleteChip,
 29	  deleteChipGroup,
 30	  setActiveId,
 31	  setTextValue,
 32	  text,
 33	  toggleCheck,
 34	}: AttributeFiltersToolbarProps<T>) => {
 35	  const { t } = useForkliftTranslation();
 36	  const active = attributes.find((attr) => attr.id === activeId) ?? attributes[0];
 37	
 38	  const checkboxSelect =
 39	    active?.kind === AttributeKind.Checkbox ? (
 40	      <FilterValueMultiSelect
 41	        attribute={active}
 42	        selected={checks[active.id] ?? new Set<string>()}
 43	        onToggle={(optId) => {
 44	          toggleCheck(active.id, optId);
 45	        }}
 46	        closeKey={active.id}
 47	      />
 48	    ) : null;
 49	
 50	  const filterGroups = attributes.map((attr) => {
 51	    const chips = chipsByAttr[attr.id] ?? [];
 52	    return (
 53	      <ToolbarFilter
 54	        key={attr.id}
 55	        categoryName={attr.label}
 56	        labels={chips}
 57	        deleteLabel={(_c: unknown, chip: string | ToolbarLabel) => {
 58	          if (typeof chip === 'string') {
 59	            deleteChip(attr.id, chip);
 60	          } else if (typeof chip.node === 'string') {
 61	            deleteChip(attr.id, chip.node);
 62	          }
 63	        }}
 64	        deleteLabelGroup={() => {
 65	          deleteChipGroup(attr.id);
 66	        }}
 67	        showToolbarItem={activeId === attr.id}
 68	      >
 69	        {attr.kind === AttributeKind.Text ? (
 70	          <SearchInput
 71	            placeholder={t('Filter by {{activeFilterLabel}}', {
 72	              activeFilterLabel:
 73	                active.id === COLUMN_IDS.Name ? active.label : active.label.toLocaleLowerCase(),
 74	            })}
 75	            value={text[attr.id] ?? ''}
 76	            onChange={(_e, value) => {
 77	              setTextValue(attr.id, value);
 78	            }}
 79	            onClear={() => {
 80	              clearText(attr.id);
 81	            }}
 82	          />
 83	        ) : (
 84	          checkboxSelect
 85	        )}
 86	      </ToolbarFilter>
 87	    );
 88	  });
 89	
 90	  return (
 91	    <ToolbarToggleGroup toggleIcon={<FilterIcon />} breakpoint="xl">
 92	      <ToolbarGroup variant="filter-group">
 93	        <ToolbarItem>
 94	          <FilterAttributeSelect
 95	            attributes={attributes}
 96	            activeId={activeId}
 97	            onChange={setActiveId}
 98	          />
 99	        </ToolbarItem>
100	        {filterGroups}
101	      </ToolbarGroup>
102	    </ToolbarToggleGroup>
103	  );
104	};

